+	if (!S_ISDIR(inode->i_mode) || !nf->nf_mark)
+		return;
+
+	/* Set up notifications for any ignored delegation events */
+	lease_mask = inode_lease_ignore_mask(inode);
+	mark = &nf->nf_mark->nfm_mark;
